sql:
SELECT proposals.proposal_id, proposals.title
FROM proposals
INNER JOIN evaluators ON proposals.submitter_id = evaluators.evaluator_id;

SELECT status 
FROM proposals 
WHERE research_area_id = 1 AND submitter_id = 2;

SELECT DISTINCT research_areas.research_area_name, research_areas.description
FROM proposals
JOIN research_areas ON proposals.research_area_id = research_areas.research_area_id;

external_knowledge:
- 'topics' refer to the titles of proposals; 
- 'biologists' refer to researchers whose affiliation is 'Biology'; 
- 'connected to the biology field' implies their work or affiliation is within 'Biology' research area.

sql:
SELECT COUNT(*) 
FROM evaluators 
WHERE specialization = 'Biology';

SELECT research_area_name
FROM research_areas
WHERE research_area_id > 5;

SELECT researchers.researcher_id, researchers.name, researchers.email, researchers.affiliation, researchers.bio
FROM researchers
INNER JOIN proposals ON researchers.researcher_id = proposals.submitter_id;

SELECT COUNT(proposal_id) AS number_of_proposals
FROM proposals
WHERE submitter_id = 1001 AND research_area_id = 1;
